Bash(node --input-type=module -e "
import { ProblemManager } from './js/problems.js';
const pm = new ProblemManager\(\);
pm.loadDemo\(\);
const p = pm.getCurrent\(\);
console.log\('Problem:', p\);
console.log\('Cols:', pm.getColumnCount\(p\)\);
console.log\('Answer:', pm.calculateAnswer\(p\)\);
console.log\('Digits:', pm.getDigits\(p.numbers[0], pm.getColumnCount\(p\)\)\);
console.log\('Carries:', pm.getCarries\(p\)\);

// Test validation
const correctAnswer = pm.calculateAnswer\(p\);
const cols = pm.getColumnCount\(p\);
const correctDigits = pm.getDigits\(correctAnswer, cols\);
console.log\('Correct digits:', correctDigits\);
console.log\('Validate correct:', pm.validateAnswer\(p, correctDigits\)\);
console.log\('Validate wrong:', pm.validateAnswer\(p, [9,9,9,9]\)\);
" 2>&1)
